    "cover": null,
    "body": "#### 1.map()\n\nfunction newMap(arr, fn){\n  const newArr \\= \\[\\];  for(let i \\= 0; i < arr.length;i++){    newArr.push(fn(arr\\[i\\], i, arr))  }  return newArr;\n}\nconst arr \\= \\[1,2,3\\];\nlet a \\= newMap(arr, function(a){\n  return a \\* 2\n})\nconsole.log(a)\n\nArray.prototype.map2 \\= function(fn, ...args){\n  const ret \\= \\[\\];  for(let i \\= 0; i < this.length;i++){    ret.push(fn(this\\[i\\], i, ...args))  }  return ret\n}\nlet b \\= arr.map2(function(item){\n  return item \\* 3\n})\nconsole.log('map2', b) //\\[3, 6, 9\\]\n\n#### 2.new操作符\n\nfunction new2(fn, ...arges){\n  const obj \\= {}  Object.setPrototypeOf(obj, fn.prototype)  const ret \\= fn.apply(obj, arges)  return ret instanceof Object ? ret : obj\n}\nfunction Test(name){\n  this.name \\= name\n}\nconst ret \\= new2(Test, 'radish');\nconsole.log(ret); //radish\n\nfunction Test(name){\n  this.name \\= name\n}\nTest.prototype.sayName \\= function(){\n  console.log(this.name)\n}\nfunction new2(fn,...args){   \n  // ...args为ES6展开符,也可以使用arguments  //先用Object创建一个空的对象,  //fn.prototype代表 用当前对象的原型去创建  const obj \\= Object.create(fn.prototype)  const rel \\= fn.apply(obj, args)  return rel instanceof Object ? rel : obj\n}\nvar newTest \\= new2(Test,'radish')\nnewTest.sayName(); // radish\n\n#### 3.JSON.stringify && JSON.parse\n\nconst obj \\= {\n  a: function () { },  b: undefined,  c: 1,  d: 'd',  f: \\[1,2,3\\]\n}\nif (!window.JSON) {\n  window.JSON \\= {    parse: function (jsonStr) {      return eval('(' + jsonStr + ')');    },    stringify: function (jsonObj) {      var result \\= '',        curVal;      if (jsonObj \\=== null) {        return String(jsonObj);      }      switch (typeof jsonObj) {        case 'number':        case 'boolean':          return String(jsonObj);        case 'string':          return '\"' + jsonObj + '\"';        case 'undefined':        case 'function':          return undefined;      }\n      switch (Object.prototype.toString.call(jsonObj)) {        case '\\[object Array\\]':          result += '\\[';          for (var i \\= 0, len \\= jsonObj.length; i < len; i++) {            curVal \\= JSON.stringify(jsonObj\\[i\\]);            result += (curVal \\=== undefined ? null : curVal) + \",\";          }          if (result !== '\\[') {            result \\= result.slice(0, \\-1);          }          result += '\\]';          return result;        case '\\[object Date\\]':          return '\"' + (jsonObj.toJSON ? jsonObj.toJSON() : jsonObj.toString()) + '\"';        case '\\[object RegExp\\]':          return \"{}\";        case '\\[object Object\\]':          result += '{';          for (i in jsonObj) {            if (jsonObj.hasOwnProperty(i)) {              curVal \\= JSON.stringify(jsonObj\\[i\\]);              if (curVal !== undefined) {                result += '\"' + i + '\":' + curVal + ',';              }            }          }          if (result !== '{') {            result \\= result.slice(0, \\-1);          }          result += '}';          return result;\n        case '\\[object String\\]':          return '\"' + jsonObj.toString() + '\"';        case '\\[object Number\\]':        case '\\[object Boolean\\]':          return jsonObj.toString();      }    }  };\n}\nconsole.log(JSON.stringify(obj))\n\n#### 4.call 或 apply\n\n//call\nFunction.prototype.newCall \\= function(target, ...args) {\n  // this 指向调用 newCall函数的对象  if (typeof this !== \"function\") {    throw new TypeError(\"not a function\")  }  target \\= target || window  target.fn \\= this // 隐式绑定，改变构造函数的调用者间接改变 this 指向  return target.fn(...args)\n};\nlet obj \\= { \n  name: 'radish' \n}\nfunction foo(...args) {\n  console.log(this.name, args)\n}\nlet s \\= foo.newCall(obj, 'a', 'b')\n// radish \\['a', 'b'\\]\n//apply\nFunction.prototype.newApply \\= function(target, ...args) {\n  // this 指向调用 newApply函数的对象  if (typeof this !== \"function\") {    throw new TypeError(\"not a function\")  }  target \\= target || window  target.fn \\= this // 隐式绑定，改变构造函数的调用者间接改变 this 指向  args \\= arguments\\[1\\]  return target.fn(...args)\n};\nlet obj \\= { \n  name: 'radish' \n}\nfunction foo(...args) {\n  console.log(this.name, args)\n}\nlet s \\= foo.newApply(obj, \\['a', 'b'\\])\n\n#### 5.Object.create()\n\nfunction \\_create(o){\n  function F(){}  F.prototype \\= o  return new F()\n}\nconst obj \\= {\n  name: 'radish'\n}\nconst a \\= \\_create(obj)\nconsole.log('a', a.name) // radish\n\n#### 6.setTimeout模拟setInterval\n\nfunction setInter(s,fn){\n  let timeOut \\= (s,fn)\\=>{      setTimeout(()\\=>{        fn();        timeOut(s,fn);      },s)  }  timeOut(s,fn);\n}\n \n//调用上面的方法\nsetInter(3000,()\\=>{console.log(\"hello radish!\")})\n\n#### 7.防抖\n\nlodash debounce 地址： [https://github.com/lodash/lodash/blob/master/debounce.js](https://github.com/lodash/lodash/blob/master/debounce.js)",
